"use strict";(self.webpackChunktemporal_documentation=self.webpackChunktemporal_documentation||[]).push([["87467"],{19998(e){e.exports=JSON.parse('{"tag":{"label":"Self-hosting","permalink":"/tags/self-hosting","allTagsPath":"/tags","count":18,"items":[{"id":"cloud/migrate/automated","title":"Automated migration","description":"Automated migration is designed to provide a zero-downtime, secure means of migrating to Temporal Cloud. This guide outlines the current process for transitioning workflows from a self-hosted setup to one hosted within Temporal Cloud.","permalink":"/cloud/migrate/automated"},{"id":"production-deployment/data-encryption","title":"Codec Server - Temporal Platform feature guide","description":"Encrypt data in Temporal Server to secure Workflow, Activity, and Worker information. Use custom Payload Codecs for encryption/decryption, set up Codec Servers for remote decoding, and ensure secure access.","permalink":"/production-deployment/data-encryption"},{"id":"production-deployment/self-hosted-guide/deployment","title":"Deploying a Temporal Service","description":"Deploy a Temporal Service using Docker, Kubernetes, or from scratch. Requires a database such as Apache Cassandra, MySQL, or PostgreSQL. Customize setup for your infrastructure and tooling.","permalink":"/self-hosted-guide/deployment"},{"id":"production-deployment/self-hosted-guide/embedded-server","title":"Embedding Temporal server as a Go library","description":"Run Temporal server as an embedded Go library for testing and development. Learn how to use temporal.NewServer() to run Temporal server in-process.","permalink":"/self-hosted-guide/embedded-server"},{"id":"production-deployment/self-hosted-guide/namespaces","title":"Managing Namespaces","description":"How to create and manage Namespaces in open source Temporal, including registration, configuration, and security.","permalink":"/self-hosted-guide/namespaces"},{"id":"cloud/migrate/manual","title":"Manual migration","description":"Migrating to Temporal Cloud from self-hosted Temporal Service varies by Workflow requirements. This guide covers changing Client code, Workflow migration strategies, and necessary code adjustments.","permalink":"/cloud/migrate/manual"},{"id":"production-deployment/self-hosted-guide/monitoring","title":"Monitor Temporal Platform metrics","description":"Monitor and health check a self-hosted Temporal Platform using Prometheus, StatsD, and M3 to track Temporal Service, Client, and Worker metrics for performance and issue troubleshooting.","permalink":"/self-hosted-guide/monitoring"},{"id":"production-deployment/self-hosted-guide/archival","title":"Self-hosted Archival setup","description":"Configure Archival to store closed Workflow Event Histories and Visibility records in blob storage.","permalink":"/self-hosted-guide/archival"},{"id":"production-deployment/self-hosted-guide/multi-cluster-replication","title":"Self-hosted Multi-Cluster Replication","description":"Multi-Cluster Replication in Temporal ensures asynchronous replication of Workflow Executions from active to passive Clusters for backup and state reconstruction, enabling seamless failovers.","permalink":"/self-hosted-guide/multi-cluster-replication"},{"id":"production-deployment/self-hosted-guide/nexus","title":"Self-hosted Temporal Nexus","description":"Use Nexus in your self-hosted Temporal Service.","permalink":"/production-deployment/self-hosted-guide/nexus"},{"id":"production-deployment/self-hosted-guide/defaults","title":"Self-hosted Temporal Service defaults","description":"Explore the Temporal Platform defaults, limits, and configurations, including Workflow Execution, Activity, Worker, and Payload size constraints. Learn about error and warning thresholds.","permalink":"/self-hosted-guide/defaults"},{"id":"production-deployment/self-hosted-guide/index","title":"Self-hosted Temporal Service guide","description":"Discover how to self-host the open-source Temporal Service to orchestrate durable applications, or consider using Temporal Cloud for ease of use. Start with our tutorials and dev guide.","permalink":"/self-hosted-guide"},{"id":"production-deployment/self-hosted-guide/visibility","title":"Self-hosted Visibility feature setup","description":"A Visibility store is essential for your Temporal Service, supporting features like batch operations and Search Attribute-based filtering for Workflow Executions. For current self-hosted deployments, use advanced Visibility on PostgreSQL 12+, MySQL 8.0.17+, SQLite 3.31.0+, Elasticsearch, or OpenSearch.","permalink":"/self-hosted-guide/visibility"},{"id":"production-deployment/self-hosted-guide/server-frontend-api-reference","title":"Server frontend API reference","description":"Easily interact with the Temporal Server via Client SDKs or CLI, or use the gRPC API for Workflow operations. Access code examples and API docs at api-docs.temporal.io.","permalink":"/self-hosted-guide/server-frontend-api-reference"},{"id":"production-deployment/index","title":"Temporal Platform production deployments","description":"Elevate your durable application to production with ease by deploying your code on your infrastructure, using Temporal Cloud for a fully-managed service or self-hosting it.","permalink":"/production-deployment"},{"id":"production-deployment/self-hosted-guide/security","title":"Temporal Platform security features","description":"Discover comprehensive security features of the Temporal Platform, including secure network communication with TLS and mTLS, robust authentication, customizable authorization, and single sign-on integration to protect your data and operations.","permalink":"/self-hosted-guide/security"},{"id":"production-deployment/self-hosted-guide/checklist","title":"Temporal Platform\'s production readiness checklist","description":"Optimize your Temporal Service for production with scaling, metrics, load testing, and effective workflow versioning techniques. Ensure robust performance and future-proof your workflows.","permalink":"/self-hosted-guide/production-checklist"},{"id":"production-deployment/self-hosted-guide/upgrade-server","title":"Upgrade the Temporal Server","description":"Upgrade your Temporal Server effectively. Follow our step-by-step guide for seamless upgrades, ensuring data compatibility and schema alignment.","permalink":"/self-hosted-guide/upgrade-server"}],"unlisted":false}}')}}]);